using System.Reflection;
var asm = Assembly.LoadFrom(args[0]);

// Find AIAgent and its methods
foreach (var t in asm.GetExportedTypes().Where(t => t.Name == "AIAgent" || t.Name == "ChatClientAgent"))
{
    Console.WriteLine($"\n=== {t.FullName} ===");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    {
        var pars = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({pars})");
    }
}

// Check if there's a MaxIterations somewhere
foreach (var t in asm.GetExportedTypes())
{
    foreach (var p in t.GetProperties())
    {
        if (p.Name.Contains("Max", StringComparison.OrdinalIgnoreCase) || p.Name.Contains("Iteration", StringComparison.OrdinalIgnoreCase))
            Console.WriteLine($"\n  {t.Name}.{p.Name}: {p.PropertyType.Name}");
    }
}
EOF
