using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notepad = new Notepad();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearch, "web_search",
        "Searches the web for the given query and returns a list of result snippets."),
    AIFunctionFactory.Create(notepad.SaveNote, "save_note",
        "Saves an important finding as a note for later use in the summary."),
    AIFunctionFactory.Create(notepad.GetNotes, "get_notes",
        "Returns all notes saved so far."),
};

// --- Chat client with function-calling middleware ----------------------------

IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation(o => o.MaximumIterationsPerRequest = 10)
    .Build();

// --- Agent -------------------------------------------------------------------

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic:
        1. Use web_search to find relevant information (make 2-4 searches with varied queries).
        2. Use save_note to record each key finding.
        3. After researching, use get_notes to review your findings.
        4. Produce a well-structured summary with sections and source references.
        Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches topics via web search and summarizes findings",
    tools: tools);

// --- Run ---------------------------------------------------------------------

Console.WriteLine("╔═══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent                  ║");
Console.WriteLine("╚═══════════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync($"Research the following topic and provide a summary: {topic}",
    session, runOptions);

Console.WriteLine("── Research Summary ────────────────────────\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n── Notes Collected ─────────────────────────\n");

var allNotes = notepad.GetNotes();
if (allNotes.Count == 0)
{
    Console.WriteLine("(no notes were saved)");
}
else
{
    for (int i = 0; i < allNotes.Count; i++)
    {
        Console.WriteLine($"  {i + 1}. {allNotes[i]}");
    }
}

Console.WriteLine();

// --- Tool implementations ----------------------------------------------------

/// <summary>Simulates a web search by calling a free search API or returning structured mock results.</summary>
[Description("Searches the web for the given query and returns result snippets.")]
static async Task<string> WebSearch([Description("The search query")] string query)
{
    Console.WriteLine($"  🔍  Searching: \"{query}\"");

    try
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
        http.Timeout = TimeSpan.FromSeconds(10);

        // Use DuckDuckGo Instant Answer API (free, no key required)
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1&skip_disambig=1";
        var json = await http.GetStringAsync(url);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var results = new StringBuilder();

        // Abstract (main answer)
        var abstractText = root.GetProperty("Abstract").GetString();
        var abstractSource = root.GetProperty("AbstractSource").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.AppendLine($"[{abstractSource}] {abstractText}");
        }

        // Related topics
        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            int count = 0;
            foreach (var item in topics.EnumerateArray())
            {
                if (count >= 5) break;
                var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    var firstUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                    results.AppendLine($"- {text} (source: {firstUrl})");
                    count++;
                }
            }
        }

        if (results.Length == 0)
        {
            results.AppendLine($"No detailed results found for '{query}'. Try a more specific query.");
        }

        return results.ToString();
    }
    catch (Exception ex)
    {
        return $"Search failed ({ex.Message}). Try rephrasing the query.";
    }
}

// --- Notepad tool class ------------------------------------------------------

/// <summary>A simple in-memory notepad for the agent to store research findings.</summary>
sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Saves a research finding as a note.")]
    public string SaveNote([Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝  Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Returns all notes collected so far.")]
    public IReadOnlyList<string> GetNotes() => _notes.AsReadOnly();
}

